module RefModule(
input             clk,
input             rst_n,
input   [31:0]    pc_in,
output  [31:0]    pc_out
);reg   [31:0]   pcreg_out;

always @(posedge clk or negedge rst_n)
begin
    if(!rst_n)
        pcreg_out <= 32'b0;
    else
        pcreg_out <= pc_in;
end

wire __pc_out_tmp = pcreg_out;
assign pc_out = __pc_out_tmp;

endmodule
